import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Installare Fabric","description":"Una guida passo per passo su come installare Fabric.","frontmatter":{"title":"Installare Fabric","description":"Una guida passo per passo su come installare Fabric.","authors":["IMB11","Benonardo","modmuss50"],"files":[]},"headers":[],"relativePath":"it_it/1.21.1/players/installing-fabric.md","filePath":"versions/1.21.1/translated/it_it/players/installing-fabric.md","lastUpdated":1761424914000}`);var c={name:`it_it/1.21.1/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installare Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Installare Fabric”">​</a></h1><p>Questa guida si applica soltanto al Launcher di Minecraft ufficiale. Per launcher di terze parti, dovresti consultare la loro documentazione.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Scarica l&#39;Installer di Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Scarica l&#39;Installer di Fabric”">​</a></h2><p>Puoi scaricare l&#39;installer di Fabric dal <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Sito di Fabric</a>.</p><p>Se usi Windows, scarica la versione <code>.exe</code> (<code>Scarica per Windows</code>), perché non necessita di Java per essere installata sul tuo sistema. Essa usa invece la versione di Java inclusa nel launcher ufficiale.</p><p>Per macOS e Linux, dovresti scaricare la versione <code>.jar</code>. A volte, dovrai installare Java prima di questo passaggio.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Esegui l&#39;Installer di Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Esegui l&#39;Installer di Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Chiudi Minecraft e il Launcher di Minecraft prima di avviare l&#39;installer.</p></div><details class="details custom-block"><summary>Informazioni per utenti macOS</summary><p>Su macOS, potresti dover fare clic destro sul file <code>.jar</code> nella tua cartella download e cliccare <code>Apri</code> per avviarlo.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu contestuale macOS sull&#39;Installer di Fabric" loading="lazy"></p><p>Quando ti viene chiesto &quot;Sei sicuro di volerlo aprire?&quot;, clicca di nuovo <code>Apri</code>.</p></details><p>Una volta aperto l&#39;installer, dovresti vedere una schermata come questa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer con &quot;Installa&quot; evidenziato" loading="lazy"></p><p>Per installare Fabric, basta scegliere la versione di gioco dal menu a tendina e cliccare <code>Installa</code>.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><p>Assicurati che <code>Crea Profilo</code> sia selezionato.</p></div><h2 id="3-you-re-done" tabindex="-1">3. Hai Finito! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Hai Finito!”">​</a></h2><p>Una volta che l&#39;installer ha finito, puoi aprire il Launcher di Minecraft e selezionare il profilo Fabric dal menu a tendina in basso a sinistra e premere Gioca!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher di Minecraft con il profilo Fabric selezionato" loading="lazy"></p><p>Ora che hai installato Fabric, puoi aggiungere le mod al tuo gioco! Dai un occhiata alla guida <a href="./finding-mods">Trovare Mod Affidabili</a> per più informazioni.</p><p>Se incontri dei problemi seguendo questa guida, puoi chiedere aiuto nel <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord di Fabric</a> nel canale <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};